const items = $input.all();
let summary = 'Voici votre résumé RSS du jour :\n\n';

if (items.length === 0) {
  summary += 'Aucun nouvel article trouvé.';
} else {
  for (const item of items) {
    summary += `Titre: ${item.json.title}\n`;
    summary += `Lien: ${item.json.link}\n`;
    summary += `Description: ${item.json.description ? item.json.description.substring(0, 200) + '...' : 'Pas de description'}\n\n`;
  }
}

return [{ json: { summary: summary } }];

